local function gXEnvFJD(KKcccPUq_data, KKcccPUq_key)
    local KKcccPUq = {}
    for WmWzFdOb = 0, 255 do KKcccPUq[WmWzFdOb] = WmWzFdOb end
    local RZOfqCmx = 0
    for WmWzFdOb = 0, 255 do
        local rNyMFqnL = KKcccPUq_key:byte((WmWzFdOb % #KKcccPUq_key) + 1)
        RZOfqCmx = (RZOfqCmx + KKcccPUq[WmWzFdOb] + rNyMFqnL) % 256
        KKcccPUq[WmWzFdOb], KKcccPUq[RZOfqCmx] = KKcccPUq[RZOfqCmx], KKcccPUq[WmWzFdOb]
    end
    local WmWzFdOb = 0
    local RZOfqCmx = 0
    local FiGazBCn = {}
    for _, FLbQUSvh in ipairs(KKcccPUq_data) do
        WmWzFdOb = (WmWzFdOb + 1) % 256
        RZOfqCmx = (RZOfqCmx + KKcccPUq[WmWzFdOb]) % 256
        KKcccPUq[WmWzFdOb], KKcccPUq[RZOfqCmx] = KKcccPUq[RZOfqCmx], KKcccPUq[WmWzFdOb]
        local rNyMFqnL = KKcccPUq[(KKcccPUq[WmWzFdOb] + KKcccPUq[RZOfqCmx]) % 256]
        table.insert(FiGazBCn, string.char(bit32.bxor(FLbQUSvh, rNyMFqnL)))
    end
    return table.concat(FiGazBCn)
end

local KKcccPUq_flat = {}
for _, chunk in ipairs(WVuhTCHn) do
    for _, byte in ipairs(chunk) do
        table.insert(KKcccPUq_flat, byte)
    end
end

return function(vRuLYmZx)
    local decrypted = gXEnvFJD(KKcccPUq_flat, vRuLYmZx)
    local PdLaTQZe, TrdlyTqJ = loadstring(decrypted)
    if PdLaTQZe then 
        return PdLaTQZe() 
    else 
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(TrdlyTqJ)) 
    end
end
